import { pipe, tap } from 'wonka'
import type { Exchange, Operation } from 'urql'
import { posthog, posthogEnabled } from './posthog'

function getOperationName(op: Operation): string {
  const def = op.query.definitions.find(
    (d) => d.kind === 'OperationDefinition',
  )
  return (def && 'name' in def && def.name?.value) || 'unknown'
}

export const posthogExchange: Exchange =
  ({ forward }) =>
  (ops$) => {
    if (!posthogEnabled) return forward(ops$)

    return pipe(
      forward(ops$),
      tap((result) => {
        const errors = result.error?.graphQLErrors
        if (errors && errors.length > 0) {
          posthog.capture('graphql_error', {
            operation_name: getOperationName(result.operation),
            errors: errors.map((e) => e.message),
          })
        }
      }),
    )
  }

